21	  PR_MAX_NOTE,
22	} from "./constants";
23	import styles from "./PianoRollEditor.module.css";
24	
25	const DEFAULT_VIEW: PianoRollViewState = {
26	  scrollX: 0,
27	  scrollY: PR_DEFAULT_SCROLL_Y,
28	  pixelsPerSecond: PR_DEFAULT_PPS,
29	  noteHeight: PR_DEFAULT_NOTE_HEIGHT,
30	  keyboardWidth: PR_KEYBOARD_WIDTH,
31	};
32	
33	const MIN_PPS = 20;
34	const MAX_PPS = 500;
35	const ZOOM_FACTOR = 1.1;
36	
37	const SNAP_OPTIONS: readonly PianoRollGridSnap[] = [
38	  "1/4",
39	  "1/8",
40	  "1/16",
41	  "1/8T",
42	  "1/16T",
43	];
44	
45	type PianoRollEditorProps = {
46	  clipId: string | null;
47	  onNotePreview?: (note: number, velocity: number) => void;
48	  onNotePreviewEnd?: (note: number) => void;
49	};
50	
51	export function PianoRollEditor({
52	  clipId,
53	  onNotePreview,
54	  onNotePreviewEnd,
55	}: PianoRollEditorProps): React.JSX.Element {
56	  const canvasRef = useRef<HTMLCanvasElement>(null);
57	  const rafRef = useRef(0);
58	  const [tool, setTool] = useState<PianoRollTool>("pencil");
59	  const [gridSnap, setGridSnap] = useState<PianoRollGridSnap>("1/8");
60	  const [view, setView] = useState(DEFAULT_VIEW);
61	
62	  const interactions = usePianoRollInteractions(
63	    clipId,
64	    view,
65	    tool,
66	    gridSnap,
67	    onNotePreview,
68	    onNotePreviewEnd,
69	  );
70	
71	  // Store selectors
72	  const clips = useDawStore((s) => s.clips);
73	  const selectedNoteIds = useDawStore((s) => s.selectedNoteIds);
74	  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
75	  const bpm = useDawStore((s) => s.bpm);
76	  const transportState = useDawStore((s) => s.transportState);
77	
78	  // Derive clip data
79	  const clip = clipId !== null ? clips[clipId] : undefined;
80	  const notes = useMemo(
81	    () => (clip !== undefined && isMidiClip(clip) ? clip.noteEvents : []),
82	    [clip],
83	  );
84	  const clipStartTime = clip !== undefined ? clip.startTime : 0;
85	  const clipDuration = clip !== undefined ? clip.duration : 4;
86	
87	  // Keyboard commands
88	  const { deleteSelectedNotes } = interactions;
89	  const registry = useMemo(() => {
90	    const reg = new CommandRegistry();
91	    reg.register({
92	      id: "piano-roll.tool.pencil",
93	      label: "Pencil Tool",
94	      execute() {
95	        setTool("pencil");
96	      },
97	    });
98	    reg.register({
99	      id: "piano-roll.tool.select",
100	      label: "Select Tool",
101	      execute() {
102	        setTool("select");
103	      },
104	    });
105	    reg.register({
106	      id: "piano-roll.tool.erase",
107	      label: "Erase Tool",
108	      execute() {
109	        setTool("erase");
110	      },
111	    });
112	    reg.register({
113	      id: "piano-roll.delete-selected",
114	      label: "Delete Selected Notes",
115	      execute() {
116	        deleteSelectedNotes();
117	      },
118	    });
119	    return reg;
120	  }, [deleteSelectedNotes]);
121	
122	  const shortcuts = useMemo(() => {
123	    const map = new ShortcutMap();
124	    map.bind({ key: "p", commandId: "piano-roll.tool.pencil" });
125	    map.bind({ key: "s", commandId: "piano-roll.tool.select" });
126	    map.bind({ key: "e", commandId: "piano-roll.tool.erase" });
127	    map.bind({ key: "Delete", commandId: "piano-roll.delete-selected" });
128	    map.bind({ key: "Backspace", commandId: "piano-roll.delete-selected" });
129	    return map;
130	  }, []);
131	
132	  useKeyboardShortcuts(registry, shortcuts);
133	
134	  // Render loop
135	  const render = useCallback((): void => {
136	    const canvas = canvasRef.current;
137	    if (canvas === null) return;
138	    const ctx = canvas.getContext("2d");
139	    if (ctx === null) return;
140	
141	    const rect = canvas.getBoundingClientRect();
142	    renderPianoRoll({
143	      ctx,
144	      width: rect.width,
145	      height: rect.height,
146	      view,
147	      notes,
148	      selectedNoteIds: [...selectedNoteIds],
149	      cursorSeconds,
150	      bpm,
151	      clipStartTime,
152	      clipDuration,
153	      tool,
154	      velocityLaneHeight: PR_VELOCITY_LANE_HEIGHT,
155	    });
156	  }, [
157	    view,
158	    notes,
159	    selectedNoteIds,
160	    cursorSeconds,
161	    bpm,
162	    clipStartTime,
163	    clipDuration,
164	    tool,
165	  ]);
166	
167	  // RAF scheduling
168	  useEffect(() => {
169	    const tick = (): void => {
170	      render();
171	      if (transportState === "playing") {
172	        rafRef.current = requestAnimationFrame(tick);
173	      }
174	    };
175	
176	    rafRef.current = requestAnimationFrame(tick);
177	    return (): void => {
178	      cancelAnimationFrame(rafRef.current);
179	    };
180	  }, [render, transportState]);
181	
182	  // Canvas sizing with ResizeObserver
183	  useEffect(() => {
184	    const canvas = canvasRef.current;
185	    if (canvas === null) return;
186	    const parent = canvas.parentElement;
187	    if (parent === null) return;
188	
189	    const resizeCanvas = (): void => {
190	      const dpr = window.devicePixelRatio;
191	      const rect = parent.getBoundingClientRect();
192	      canvas.width = rect.width * dpr;
193	      canvas.height = rect.height * dpr;
194	      canvas.style.width = `${String(rect.width)}px`;
195	      canvas.style.height = `${String(rect.height)}px`;
196	
197	      const ctx = canvas.getContext("2d");
198	      if (ctx !== null) {
199	        ctx.scale(dpr, dpr);
200	      }
201	      render();
202	    };
203	
204	    if (typeof ResizeObserver === "undefined") return;
205	
206	    const observer = new ResizeObserver(resizeCanvas);
207	    observer.observe(parent);
208	    resizeCanvas();
209	
210	    return (): void => {
211	      observer.disconnect();
212	    };
213	  }, [render]);
214	
215	  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
216	  // Attached via useEffect with { passive: false } so preventDefault() works
217	  useEffect(() => {
218	    const canvas = canvasRef.current;
219	    if (canvas === null) return;
220	
221	    const handleWheel = (e: WheelEvent): void => {
222	      e.preventDefault();
223	
224	      if (e.ctrlKey || e.metaKey) {
225	        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
226	        setView((prev) => ({
227	          ...prev,
228	          pixelsPerSecond: Math.min(
229	            MAX_PPS,
230	            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
231	          ),
232	        }));
233	      } else if (e.shiftKey) {
234	        setView((prev) => ({
235	          ...prev,
236	          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
237	        }));
238	      } else {
239	        setView((prev) => ({
240	          ...prev,
241	          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
242	          scrollY: Math.min(
243	            PR_MAX_NOTE,
244	            Math.max(PR_MIN_NOTE, prev.scrollY - e.deltaY / prev.noteHeight),
245	          ),
246	        }));
247	      }
248	    };
249	
250	    canvas.addEventListener("wheel", handleWheel, { passive: false });
251	    return (): void => {
252	      canvas.removeEventListener("wheel", handleWheel);
253	    };
254	  }, []);
255	
256	  if (clipId === null) {
257	    return (
258	      <section data-testid="piano-roll-editor" className={styles["container"]}>
259	        <div className={styles["emptyState"]}>Select a MIDI clip to edit</div>
260	      </section>
261	    );
262	  }
263	
264	  return (
265	    <section data-testid="piano-roll-editor" className={styles["container"]}>
266	      <div className={styles["toolbar"]}>
267	        <button
268	          data-testid="tool-pencil"
269	          className={styles["toolButton"]}
270	          aria-pressed={tool === "pencil"}
271	          title="Pencil Tool (P)"
272	          onClick={() => {
273	            setTool("pencil");
274	          }}
275	        >
276	          Pencil
277	        </button>
278	        <button
279	          data-testid="tool-select"
280	          className={styles["toolButton"]}
281	          aria-pressed={tool === "select"}
282	          title="Select Tool (S)"
283	          onClick={() => {
284	            setTool("select");
285	          }}
286	        >
287	          Select
288	        </button>
289	        <button
290	          data-testid="tool-erase"
291	          className={styles["toolButton"]}
292	          aria-pressed={tool === "erase"}
293	          title="Erase Tool (E)"
294	          onClick={() => {
295	            setTool("erase");
296	          }}
297	        >
298	          Erase
299	        </button>
300	        <select
301	          data-testid="snap-select"
302	          className={styles["snapSelect"]}
303	          value={gridSnap}
304	          onChange={(e) => {
305	            setGridSnap(e.target.value as PianoRollGridSnap);
306	          }}
307	        >
308	          {SNAP_OPTIONS.map((opt) => (
309	            <option key={opt} value={opt}>
310	              {opt}
311	            </option>
312	          ))}
313	        </select>
314	      </div>
315	      <div className={styles["canvasWrapper"]}>
316	        <canvas
317	          ref={canvasRef}
318	          role="application"
319	          tabIndex={0}
320	          aria-label="Piano roll editor"
321	          className={styles["canvas"]}
322	          style={{ cursor: interactions.cursor }}
323	          onPointerDown={interactions.onPointerDown}
324	          onPointerMove={interactions.onPointerMove}
325	          onPointerUp={interactions.onPointerUp}
326	        />
327	      </div>
328	    </section>
329	  );
330	}
