1	/**
2	 * Effects rack for a single track.
3	 * Shows insert chain with add/remove/bypass controls.
4	 */
5	
6	import { useState, useCallback } from "react";
7	import { useEffectsStore } from "@state/effects";
8	import { useEffectsBridgeContext } from "@audio/effects/EffectsBridgeProvider";
9	import { tokens } from "@ui/tokens/tokens";
10	import { EffectPanel } from "./EffectPanel";
11	
12	const EMPTY_SLOTS: readonly never[] = [];
13	
14	// Reverb A/B: swap between convolution and algorithmic reverb
15	const REVERB_SWAP: Record<string, string> = {
16	  reverb: "freeverb",
17	  freeverb: "reverb",
18	};
19	
20	type EffectsRackProps = {
21	  trackId: string;
22	};
23	
24	export function EffectsRack({ trackId }: EffectsRackProps): React.JSX.Element {
25	  const { registry } = useEffectsBridgeContext();
26	  const availableEffects = registry.getAll();
27	
28	  const slots = useEffectsStore((s) => s.trackEffects[trackId] ?? EMPTY_SLOTS);
29	  const addEffect = useEffectsStore((s) => s.addEffect);
30	  const removeEffect = useEffectsStore((s) => s.removeEffect);
31	  const updateEffectParam = useEffectsStore((s) => s.updateEffectParam);
32	  const toggleBypass = useEffectsStore((s) => s.toggleBypass);
33	  const swapEffectType = useEffectsStore((s) => s.swapEffectType);
34	
35	  const [showSelector, setShowSelector] = useState(false);
36	
37	  const handleSwapReverb = useCallback(
38	    (
39	      slotId: string,
40	      currentTypeId: string,
41	      currentParams: Record<string, number>,
42	    ) => {
43	      const targetTypeId = REVERB_SWAP[currentTypeId];
44	      if (targetTypeId === undefined || targetTypeId === "") return;
45	      const targetFactory = registry.get(targetTypeId);
46	      if (!targetFactory) return;
47	      const newParams: Record<string, number> = {};
48	      for (const p of targetFactory.definition.parameters) {
49	        newParams[p.key] = p.default;
50	      }
51	      // Preserve mix level for meaningful A/B comparison
52	      const currentMix = currentParams.mix;
53	      if (currentMix !== undefined) {
54	        newParams.mix = currentMix;
55	      }
56	      swapEffectType(trackId, slotId, targetTypeId, newParams);
57	    },
58	    [trackId, swapEffectType, registry],
59	  );
60	
61	  const handleAdd = useCallback(
62	    (typeId: string) => {
63	      const factory = registry.get(typeId);
64	      if (!factory) return;
65	
66	      const id = `${typeId}-${crypto.randomUUID().slice(0, 8)}`;
67	      const params: Record<string, number> = {};
68	      for (const p of factory.definition.parameters) {
69	        params[p.key] = p.default;
70	      }
71	
72	      addEffect(trackId, { id, typeId, bypassed: false, params });
73	      setShowSelector(false);
74	    },
75	    [trackId, addEffect, registry],
76	  );
77	
78	  return (
79	    <div
80	      data-testid="effects-rack"
81	      style={{
82	        display: "flex",
83	        flexDirection: "column",
84	        gap: tokens.space[1],
85	        padding: tokens.space[2],
86	        borderTop: "2px solid var(--color-gray-700)",
87	        backgroundColor: tokens.color.gray900,
88	        minHeight: 40,
89	      }}
90	    >
91	      {slots.map((slot) => {
92	        const factory = registry.get(slot.typeId);
93	        if (!factory) return null;
94	
95	        const isReverbType = slot.typeId in REVERB_SWAP;
96	        const swapTarget = REVERB_SWAP[slot.typeId];
97	        const swapTargetFactory =
98	          swapTarget !== undefined && swapTarget !== ""
99	            ? registry.get(swapTarget)
100	            : undefined;
101	
102	        return (
103	          <EffectPanel
104	            key={slot.id}
105	            definition={factory.definition}
106	            params={slot.params}
107	            bypassed={slot.bypassed}
108	            onParamChange={(key, value) => {
109	              updateEffectParam(trackId, slot.id, key, value);
110	            }}
111	            onBypassToggle={() => {
112	              toggleBypass(trackId, slot.id);
113	            }}
114	            onRemove={() => {
115	              removeEffect(trackId, slot.id);
116	            }}
117	            onSwapType={
118	              isReverbType
119	                ? () => {
120	                    handleSwapReverb(slot.id, slot.typeId, slot.params);
121	                  }
122	                : undefined
123	            }
124	            swapLabel={swapTargetFactory?.definition.name}
125	          />
126	        );
127	      })}
128	
129	      {showSelector ? (
130	        <div
131	          style={{
132	            display: "flex",
133	            flexWrap: "wrap",
134	            gap: tokens.space[1],
135	          }}
136	        >
137	          {availableEffects.map((f) => (
138	            <button
139	              key={f.definition.id}
140	              type="button"
141	              onClick={() => {
142	                handleAdd(f.definition.id);
143	              }}
144	              style={{
145	                fontFamily: tokens.font.mono,
146	                fontSize: tokens.text.xs,
147	                border: "2px solid var(--color-gray-700)",
148	                background: "transparent",
149	                color: tokens.color.white,
150	                cursor: "pointer",
151	                padding: `${String(tokens.space[1])}px ${String(tokens.space[2])}px`,
152	              }}
153	            >
154	              {f.definition.name}
155	            </button>
156	          ))}
157	          <button
158	            type="button"
159	            onClick={() => {
160	              setShowSelector(false);
161	            }}
162	            style={{
163	              fontFamily: tokens.font.mono,
164	              fontSize: tokens.text.xs,
165	              border: "2px solid var(--color-gray-700)",
166	              background: "transparent",
167	              color: tokens.color.gray300,
168	              cursor: "pointer",
169	              padding: "4px 8px",
170	            }}
171	          >
172	            Cancel
173	          </button>
174	        </div>
175	      ) : (
176	        <button
177	          type="button"
178	          aria-label="Add effect"
179	          onClick={() => {
180	            setShowSelector(true);
181	          }}
182	          style={{
183	            fontFamily: tokens.font.mono,
184	            fontSize: tokens.text.xs,
185	            border: "2px solid var(--color-gray-700)",
186	            background: "transparent",
187	            color: tokens.color.green,
188	            cursor: "pointer",
189	            padding: "4px 8px",
190	            alignSelf: "flex-start",
191	          }}
192	        >
193	          + INSERT
194	        </button>
195	      )}
196	    </div>
197	  );
198	}
