1	import { useEffect, useState, useCallback } from "react";
2	import { Modal } from "@ui/primitives/Modal";
3	import { Button } from "@ui/primitives/Button";
4	import type { SessionStorage, SessionListEntry } from "@state/session/index";
5	
6	type SessionBrowserProps = {
7	  open: boolean;
8	  storage: SessionStorage;
9	  onLoad: (id: string) => void;
10	  onClose: () => void;
11	};
12	
13	export function SessionBrowser({
14	  open,
15	  storage,
16	  onLoad,
17	  onClose,
18	}: SessionBrowserProps): React.JSX.Element {
19	  const [sessions, setSessions] = useState<SessionListEntry[]>([]);
20	  const [error, setError] = useState<string | null>(null);
21	
22	  const refresh = useCallback((): void => {
23	    void storage
24	      .listSessions()
25	      .then((list) => {
26	        setSessions(list);
27	        setError(null);
28	      })
29	      .catch(() => {
30	        setError("Failed to load sessions.");
31	      });
32	  }, [storage]);
33	
34	  useEffect(() => {
35	    if (open) {
36	      refresh();
37	    }
38	  }, [open, refresh]);
39	
40	  function handleDelete(id: string): void {
41	    void storage
42	      .deleteSession(id)
43	      .then(refresh)
44	      .catch(() => {
45	        setError("Failed to delete session.");
46	      });
47	  }
48	
49	  return (
50	    <Modal open={open} onClose={onClose} title="Sessions">
51	      {error !== null ? (
52	        <div>
53	          <p style={{ color: "var(--color-error)" }}>{error}</p>
54	          <Button size="sm" onClick={refresh}>
55	            Retry
56	          </Button>
57	        </div>
58	      ) : sessions.length === 0 ? (
59	        <p>No saved sessions</p>
60	      ) : (
61	        <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
