66	                display: "flex",
67	                alignItems: "center",
68	                gap: "var(--space-2)",
69	                padding: "var(--space-1) 0",
70	              }}
71	            >
72	              <span style={{ flex: 1 }}>{s.name}</span>
73	              <Button
74	                size="sm"
75	                data-testid={`load-${s.id}`}
76	                onClick={() => {
77	                  onLoad(s.id);
78	                }}
79	              >
80	                Load
81	              </Button>
82	              <Button
83	                size="sm"
84	                variant="ghost"
85	                data-testid={`delete-${s.id}`}
86	                onClick={() => {
87	                  handleDelete(s.id);
88	                }}
89	              >
90	                Delete
91	              </Button>
92	            </li>
93	          ))}
94	        </ul>
95	      )}
96	    </Modal>
97	  );
98	}
