136	      }
137	    },
138	    [handleImport],
139	  );
140	
141	  const panelClass = isDragging
142	    ? [styles["panel"], styles["dragging"]].join(" ")
143	    : (styles["panel"] ?? "");
144	
145	  return (
146	    <section
147	      data-testid="media-pool-panel"
148	      className={panelClass}
149	      {...handlers}
150	    >
