152	        <span>MEDIA POOL</span>
153	        <button
154	          type="button"
155	          className={styles["importBtn"]}
156	          onClick={onImportClick}
157	          disabled={isImporting}
158	        >
159	          {isImporting ? "IMPORTING..." : "IMPORT"}
160	        </button>
161	        <input
162	          ref={fileInputRef}
163	          type="file"
164	          accept="audio/wav,audio/mpeg,audio/ogg,audio/flac,.wav,.mp3,.ogg,.flac"
165	          multiple
166	          style={{ display: "none" }}
167	          onChange={onFileChange}
168	        />
169	      </div>
170	
171	      {(errors.length > 0 || removeError !== null) && (
172	        <div className={styles["error"]}>
173	          {errors.map((err, i) => (
174	            <div key={i}>{formatError(err)}</div>
175	          ))}
176	          {removeError !== null && <div>{removeError}</div>}
177	          <button
178	            type="button"
179	            className={styles["dismissBtn"]}
180	            onClick={() => {
