1	import { useEffect, useRef } from "react";
2	import styles from "./Modal.module.css";
3	
4	type ModalProps = {
5	  open: boolean;
6	  onClose: () => void;
7	  title: string;
8	  children: React.ReactNode;
9	};
10	
11	export function Modal({
12	  open,
13	  onClose,
14	  title,
15	  children,
16	}: ModalProps): React.JSX.Element {
17	  const dialogRef = useRef<HTMLDialogElement>(null);
18	  const previousFocusRef = useRef<HTMLElement | null>(null);
19	
20	  useEffect(() => {
21	    const dialog = dialogRef.current;
22	    if (dialog === null) return;
23	
24	    if (open) {
25	      previousFocusRef.current = document.activeElement as HTMLElement | null;
26	      if (!dialog.open) {
27	        dialog.showModal();
28	      }
29	      dialog.setAttribute("open", "");
30	      dialog.focus();
31	    } else {
32	      if (dialog.open) {
33	        dialog.close();
34	      }
35	      dialog.removeAttribute("open");
36	      previousFocusRef.current?.focus();
37	      previousFocusRef.current = null;
38	    }
39	  }, [open]);
40	
41	  useEffect(() => {
42	    const dialog = dialogRef.current;
43	    if (dialog === null) return;
44	
45	    const handleClose = (): void => {
46	      onClose();
47	    };
48	
49	    const handleKeyDown = (e: KeyboardEvent): void => {
50	      if (e.key !== "Tab" || !dialog.open) return;
51	
52	      const focusable = dialog.querySelectorAll<HTMLElement>(
53	        'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])',
54	      );
55	      if (focusable.length === 0) return;
56	
57	      const first = focusable[0];
58	      const last = focusable[focusable.length - 1];
59	      if (first === undefined || last === undefined) return;
60	
61	      if (e.shiftKey) {
62	        if (
63	          document.activeElement === first ||
64	          document.activeElement === dialog
65	        ) {
66	          e.preventDefault();
67	          last.focus();
68	        }
69	      } else {
70	        if (document.activeElement === last) {
71	          e.preventDefault();
72	          first.focus();
73	        }
74	      }
75	    };
76	
77	    dialog.addEventListener("close", handleClose);
78	    dialog.addEventListener("keydown", handleKeyDown);
79	    return () => {
80	      dialog.removeEventListener("close", handleClose);
81	      dialog.removeEventListener("keydown", handleKeyDown);
82	    };
83	  }, [onClose]);
84	
85	  return (
86	    <dialog
87	      ref={dialogRef}
88	      className={styles.dialog}
89	      data-testid="modal-dialog"
90	      tabIndex={-1}
91	    >
92	      <div className={styles.titleBar}>{title}</div>
93	      <div className={styles.body}>{children}</div>
94	    </dialog>
95	  );
96	}
