1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import type {
3	  MediaPool,
4	  WaveformPeaks,
5	  MediaPoolError,
6	} from "@audio/media-pool";
7	import { MediaPoolItem } from "./MediaPoolItem";
8	import { useFileDrop } from "./useFileDrop";
9	import { Spinner } from "@ui/primitives/Spinner";
10	import styles from "./MediaPoolPanel.module.css";
11	
12	type MediaPoolPanelProps = {
13	  pool: MediaPool;
14	};
15	
16	function formatError(error: MediaPoolError): string {
17	  switch (error.kind) {
18	    case "decode-failed":
19	      return `Failed to decode "${error.fileName}". Try WAV, MP3, OGG, or FLAC format.`;
20	    case "unsupported-format":
21	      return `Unsupported format: "${error.fileName}". Try WAV, MP3, OGG, or FLAC.`;
22	    case "file-too-large":
23	      return `File "${error.fileName}" is too large (max 500MB).`;
24	    case "storage-full":
25	      return `Storage full. Cannot import "${error.fileName}".`;
26	  }
27	}
28	
29	export function MediaPoolPanel({
30	  pool,
31	}: MediaPoolPanelProps): React.JSX.Element {
32	  const fileInputRef = useRef<HTMLInputElement>(null);
33	  const [version, setVersion] = useState(0);
34	  const sources = useMemo(() => pool.listSources(), [pool, version]); // eslint-disable-line react-hooks/exhaustive-deps
35	  const [peaksMap, setPeaksMap] = useState(new Map<string, WaveformPeaks>());
36	  const [errors, setErrors] = useState<MediaPoolError[]>([]);
37	  const [removeError, setRemoveError] = useState<string | null>(null);
38	  const [isImporting, setIsImporting] = useState(false);
39	  const importingRef = useRef(false);
40	  const autoDismissTimerRef = useRef(0);
41	
42	  useEffect(() => {
43	    // Load cached peaks for persisted sources
44	    void Promise.all(
45	      sources.map(async (source) => {
46	        if (peaksMap.has(source.id)) return;
47	        const peaks = await pool.getPeaks(source.id, 256);
48	        if (peaks !== undefined) {
49	          setPeaksMap((prev) => {
50	            const next = new Map(prev);
51	            next.set(source.id, peaks);
52	            return next;
53	          });
54	        }
55	      }),
56	    );
57	  }, [sources, pool]); // eslint-disable-line react-hooks/exhaustive-deps
58	
59	  const handleImport = useCallback(
60	    async (files: File[]) => {
61	      if (importingRef.current) return;
62	      importingRef.current = true;
63	      setIsImporting(true);
64	      setErrors([]);
65	      window.clearTimeout(autoDismissTimerRef.current);
66	      try {
67	        const importErrors: MediaPoolError[] = [];
68	        for (const file of files) {
69	          const result = await pool.importFile(file);
70	          if (result.ok) {
71	            const peaks = await pool.getPeaks(result.handle.id, 256);
72	            if (peaks !== undefined) {
73	              setPeaksMap((prev) => {
74	                const next = new Map(prev);
75	                next.set(result.handle.id, peaks);
76	                return next;
77	              });
78	            }
79	          } else {
80	            importErrors.push(result.error);
81	          }
82	        }
83	        if (importErrors.length > 0) {
84	          setErrors(importErrors);
85	          autoDismissTimerRef.current = window.setTimeout(() => {
86	            setErrors([]);
87	          }, 5000);
88	        }
89	        setVersion((v) => v + 1);
90	      } finally {
91	        importingRef.current = false;
92	        setIsImporting(false);
93	      }
94	    },
95	    [pool],
96	  );
97	
98	  const handleRemove = useCallback(
99	    (id: string) => {
100	      void pool
101	        .removeSource(id)
102	        .then(() => {
103	          setVersion((v) => v + 1);
104	          setPeaksMap((prev) => {
105	            const next = new Map(prev);
106	            next.delete(id);
107	            return next;
108	          });
109	        })
110	        .catch(() => {
111	          const name = pool.getSource(id)?.name ?? id;
112	          setRemoveError(`Failed to remove "${name}".`);
113	        });
114	    },
115	    [pool],
116	  );
117	
118	  const onFileDrop = useCallback(
119	    (files: File[]) => {
120	      void handleImport(files);
121	    },
122	    [handleImport],
123	  );
124	
125	  const { isDragging, handlers } = useFileDrop(onFileDrop);
126	
127	  const onImportClick = useCallback(() => {
128	    fileInputRef.current?.click();
129	  }, []);
130	
131	  const onFileChange = useCallback(
132	    (e: React.ChangeEvent<HTMLInputElement>) => {
133	      const files = e.target.files;
134	      if (files !== null && files.length > 0) {
135	        void handleImport([...files]);
136	      }
137	    },
138	    [handleImport],
139	  );
140	
141	  const panelClass = isDragging
142	    ? [styles["panel"], styles["dragging"]].join(" ")
143	    : (styles["panel"] ?? "");
144	
145	  return (
146	    <section
147	      data-testid="media-pool-panel"
148	      className={panelClass}
149	      {...handlers}
150	    >
151	      <div className={styles["header"]}>
152	        <span>MEDIA POOL</span>
153	        <button
154	          type="button"
155	          className={styles["importBtn"]}
156	          onClick={onImportClick}
157	          disabled={isImporting}
158	        >
159	          {isImporting ? "IMPORTING..." : "IMPORT"}
160	        </button>
161	        <input
162	          ref={fileInputRef}
163	          type="file"
164	          accept="audio/wav,audio/mpeg,audio/ogg,audio/flac,.wav,.mp3,.ogg,.flac"
165	          multiple
166	          style={{ display: "none" }}
167	          onChange={onFileChange}
168	        />
169	      </div>
170	
171	      {(errors.length > 0 || removeError !== null) && (
172	        <div className={styles["error"]}>
173	          {errors.map((err, i) => (
174	            <div key={i}>{formatError(err)}</div>
175	          ))}
176	          {removeError !== null && <div>{removeError}</div>}
177	          <button
178	            type="button"
179	            className={styles["dismissBtn"]}
180	            onClick={() => {
181	              window.clearTimeout(autoDismissTimerRef.current);
182	              setErrors([]);
183	              setRemoveError(null);
184	            }}
185	            aria-label="Dismiss errors"
186	          >
187	            Dismiss
188	          </button>
189	        </div>
190	      )}
191	
192	      {isImporting && (
193	        <div className={styles["importing"]}>
194	          <Spinner />
195	          <span>Importing audio...</span>
196	        </div>
197	      )}
198	
199	      {sources.length === 0 ? (
200	        <div className={styles["empty"]}>
201	          Drop audio files here or click IMPORT
202	        </div>
203	      ) : (
204	        <div className={styles["list"]}>
205	          {sources.map((source) => (
206	            <MediaPoolItem
207	              key={source.id}
208	              source={source}
209	              peaks={peaksMap.get(source.id)}
210	              onRemove={handleRemove}
211	            />
212	          ))}
213	        </div>
214	      )}
