import { useEffect, useRef, useState } from "react";
import styles from "./UndoToast.module.css";

const UNDO_WINDOW = 5000;
const FADE_DURATION = 100;

type UndoToastState = {
  message: string;
  onUndo: () => void;
};

type Phase = "visible" | "fading" | "hidden";

type UndoToastProps = {
  pending: UndoToastState | null;
  onExpired: () => void;
};

export type { UndoToastState };

export function UndoToast({
  pending,
  onExpired,
}: UndoToastProps): React.JSX.Element | null {
  const [phase, setPhase] = useState<Phase>("hidden");
  const timerRef = useRef(0);

  useEffect(() => {
    if (pending === null) {
      setPhase("hidden");
      return;
    }

    setPhase("visible");
    window.clearTimeout(timerRef.current);

    const fadeTimer = window.setTimeout(() => {
      setPhase("fading");
    }, UNDO_WINDOW - FADE_DURATION);

    const expireTimer = window.setTimeout(() => {
      setPhase("hidden");
      onExpired();
    }, UNDO_WINDOW);

    timerRef.current = expireTimer;

    return () => {
      window.clearTimeout(fadeTimer);
      window.clearTimeout(expireTimer);
    };
  }, [pending, onExpired]);

  if (phase === "hidden" || pending === null) return null;

  const toastClass = styles["toast"] ?? "";
  const hidingClass = styles["hiding"] ?? "";

  return (
    <div
      className={`${toastClass}${phase === "fading" ? ` ${hidingClass}` : ""}`}
      role="status"
      aria-live="polite"
      data-testid="undo-toast"
    >
      <span>{pending.message}</span>
      <button
        type="button"
        className={styles["undoBtn"]}
        onClick={() => {
          window.clearTimeout(timerRef.current);
          pending.onUndo();
          setPhase("hidden");
        }}
        data-testid="undo-btn"
      >
        Undo
      </button>
    </div>
  );
}

