2	 * Effects rack for a single track.
3	 * Shows insert chain with add/remove/bypass controls.
4	 */
5	
6	import { useState, useCallback } from "react";
7	import { useEffectsStore } from "@state/effects";
8	import { useEffectsBridgeContext } from "@audio/effects/EffectsBridgeProvider";
9	import { tokens } from "@ui/tokens/tokens";
10	import { EffectPanel } from "./EffectPanel";
11	
12	const EMPTY_SLOTS: readonly never[] = [];
13	
14	// Reverb A/B: swap between convolution and algorithmic reverb
15	const REVERB_SWAP: Record<string, string> = {
16	  reverb: "freeverb",
17	  freeverb: "reverb",
18	};
19	
20	type EffectsRackProps = {
21	  trackId: string;
22	};
23	
24	export function EffectsRack({ trackId }: EffectsRackProps): React.JSX.Element {
25	  const { registry } = useEffectsBridgeContext();
26	  const availableEffects = registry.getAll();
27	
28	  const slots = useEffectsStore((s) => s.trackEffects[trackId] ?? EMPTY_SLOTS);
29	  const addEffect = useEffectsStore((s) => s.addEffect);
30	  const removeEffect = useEffectsStore((s) => s.removeEffect);
31	  const updateEffectParam = useEffectsStore((s) => s.updateEffectParam);
32	  const toggleBypass = useEffectsStore((s) => s.toggleBypass);
33	  const swapEffectType = useEffectsStore((s) => s.swapEffectType);
34	
35	  const [showSelector, setShowSelector] = useState(false);
36	
37	  const handleSwapReverb = useCallback(
38	    (
39	      slotId: string,
40	      currentTypeId: string,
41	      currentParams: Record<string, number>,
42	    ) => {
43	      const targetTypeId = REVERB_SWAP[currentTypeId];
44	      if (targetTypeId === undefined || targetTypeId === "") return;
45	      const targetFactory = registry.get(targetTypeId);
46	      if (!targetFactory) return;
47	      const newParams: Record<string, number> = {};
48	      for (const p of targetFactory.definition.parameters) {
49	        newParams[p.key] = p.default;
50	      }
51	      // Preserve mix level for meaningful A/B comparison
52	      const currentMix = currentParams.mix;
53	      if (currentMix !== undefined) {
54	        newParams.mix = currentMix;
55	      }
56	      swapEffectType(trackId, slotId, targetTypeId, newParams);
57	    },
58	    [trackId, swapEffectType, registry],
59	  );
60	
