      <div style={{ display: "flex", gap: tokens.space[4] }}>
        {/* Sources */}
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            gap: tokens.space[1],
          }}
        >
          <span style={LABEL_STYLE}>SOURCES</span>
