              const destY = 20 + destIdx * 22;
              return (
                <line
                  key={route.id}
                  data-testid={`cable-${route.source}-${route.destination}`}
                  x1={0}
                  y1={srcY}
                  x2={60}
                  y2={destY}
                  stroke={SOURCE_COLORS[route.source]}
