import { useRef, useEffect } from "react";
import styles from "./StepButton.module.css";

type StepButtonProps = {
  active: boolean;
  current?: boolean;
  onToggle: () => void;
  index: number;
  tabIndex?: number;
  focused?: boolean;
  onArrowNav?: (direction: -1 | 1) => void;
};

export function StepButton({
  active,
  current = false,
  onToggle,
  index,
  tabIndex,
  focused,
  onArrowNav,
}: StepButtonProps): React.JSX.Element {
  const ref = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    if (focused) {
      ref.current?.focus();
    }
  }, [focused]);

  const classes = [
    styles["step"],
    active ? styles["active"] : undefined,
    current ? styles["current"] : undefined,
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <button
      ref={ref}
      type="button"
      className={classes}
      aria-pressed={active}
      aria-label={`Step ${String(index + 1)}`}
      tabIndex={tabIndex}
      onClick={onToggle}
      onKeyDown={(e) => {
        if (onArrowNav) {
          if (e.key === "ArrowRight") {
            e.preventDefault();
            onArrowNav(1);
          } else if (e.key === "ArrowLeft") {
            e.preventDefault();
            onArrowNav(-1);
          }
        }
      }}
    />
  );
}

