      window.clearTimeout(fadeTimer);
      window.clearTimeout(expireTimer);
    };
  }, [pending, onExpired]);

  // Derive phase from pending prop for show/hide transitions
  const isVisible = pending !== null && phase !== "hidden";

  if (phase === "hidden" || pending === null) return null;

  const toastClass = styles["toast"] ?? "";
  const hidingClass = styles["hiding"] ?? "";

