import { useEffect, useRef, useState } from "react";
import styles from "./UndoToast.module.css";

const UNDO_WINDOW = 5000;
const FADE_DURATION = 100;

type UndoToastState = {
  message: string;
  onUndo: () => void;
};

type UndoToastProps = {
  pending: UndoToastState | null;
  onExpired: () => void;
};

export type { UndoToastState };

export function UndoToast({
  pending,
  onExpired,
}: UndoToastProps): React.JSX.Element | null {
  const [fading, setFading] = useState(false);
  const timerRef = useRef(0);
  const fadeRef = useRef(0);

  useEffect(() => {
    if (pending === null) return;

    setFading(false);
    window.clearTimeout(timerRef.current);
    window.clearTimeout(fadeRef.current);

    fadeRef.current = window.setTimeout(() => {
      setFading(true);
    }, UNDO_WINDOW - FADE_DURATION);

    timerRef.current = window.setTimeout(() => {
      onExpired();
    }, UNDO_WINDOW);

    return () => {
      window.clearTimeout(fadeRef.current);
      window.clearTimeout(timerRef.current);
    };
  }, [pending, onExpired]);

  if (pending === null) return null;

  const toastClass = styles["toast"] ?? "";
  const hidingClass = styles["hiding"] ?? "";

  return (
    <div
      className={`${toastClass}${fading ? ` ${hidingClass}` : ""}`}
      role="status"
      aria-live="polite"
      data-testid="undo-toast"
    >
      <span>{pending.message}</span>
      <button
        type="button"
        className={styles["undoBtn"]}
        onClick={() => {
          window.clearTimeout(timerRef.current);
          window.clearTimeout(fadeRef.current);
          pending.onUndo();
        }}
        data-testid="undo-btn"
      >
        Undo
      </button>
    </div>
  );
}

