  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  const refresh = useCallback((): void => {
    void storage
      .listSessions()
      .then((list) => {
        setSessions(list);
        setError(null);
      })
      .catch(() => {
        setError("Failed to load sessions.");
      });
  }, [storage]);

  // Reset confirmation state when the dialog is closed and reopened
  const prevOpenRef = useRef(false);
  if (open && !prevOpenRef.current) {
    setConfirmDeleteId(null);
  }
  prevOpenRef.current = open;

  useEffect(() => {
    if (open) {
      refresh();
    }
  }, [open, refresh]);

  function handleDelete(id: string): void {
    void storage
      .deleteSession(id)
      .then(() => {
        setConfirmDeleteId(null);
        refresh();
      })
      .catch(() => {
        setConfirmDeleteId(null);
        setError("Failed to delete session.");
      });
  }

  const pendingSession = sessions.find((s) => s.id === confirmDeleteId);

  return (
    <Modal open={open} onClose={onClose} title="Sessions">
      {confirmDeleteId !== null && pendingSession !== undefined ? (
        <div data-testid="delete-confirm">
          <p>
