import { describe, it, expect, vi, beforeAll } from "vitest";
import { render, screen, within } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { ModulationMatrix } from "./ModulationMatrix";

vi.mock("@state/synth/modulation-store", () => {
  const routes: Array<{
    id: string;
    source: string;
    destination: string;
    amount: number;
    bipolar: boolean;
  }> = [];

  return {
    MOD_SOURCE_LABELS: {
      lfo1: "LFO 1",
      lfo2: "LFO 2",
      ampEnv: "Amp Env",
      filterEnv: "Filter Env",
      velocity: "Velocity",
      aftertouch: "Aftertouch",
      modWheel: "Mod Wheel",
      pitchBend: "Pitch Bend",
    },
    MOD_DEST_LABELS: {
      pitch: "Pitch",
      filterCutoff: "Filter Cutoff",
      filterRes: "Filter Res",
      amp: "Amp",
      pan: "Pan",
      lfo1Rate: "LFO 1 Rate",
      lfo2Rate: "LFO 2 Rate",
      fmDepth: "FM Depth",
    },
    useModulationStore: (selector: (s: Record<string, unknown>) => unknown) => {
      const store = {
        matrices: {
          "track-1": { routes },
        },
        initMatrix: vi.fn(),
        addRoute: vi.fn(
          (_trackId: string, source: string, destination: string) => {
            routes.push({
              id: `${source}-${destination}`,
              source,
              destination,
              amount: 0.5,
              bipolar: false,
            });
          },
        ),
        removeRoute: vi.fn(),
        updateRouteAmount: vi.fn(),
